          <View style={[styles.iconContainer, { backgroundColor: '#ef444420' }]}>
            <Ionicons name="card-outline" size={24} color="#ef4444" />
          </View>
          <View style={styles.cardContent}>
            <Text style={styles.cardTitle}>Get Your TIN</Text>
