      {/* Sticky Adaptive Banner Ad at Bottom */}
      <View style={styles.stickyAdContainer}>
        <AdBanner size={BannerAdSize.ANCHORED_ADAPTIVE_BANNER} />
      </View>
    </View>
  );
}

