import React, { useState } from 'react';
import { View, Text, StyleSheet, ScrollView, Switch, Alert, Modal, TextInput, TouchableOpacity, Linking, } from 'react-native';
import { useRouter } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import useTheme from '@/hooks/userTheme';
import { useAuth } from '@/contexts/AuthContext';
import { useSecurity } from '@/contexts/SecurityContext';
import { useNotifications } from '@/contexts/NotificationContext';
import DateTimePicker from '@react-native-community/datetimepicker';

export default function SettingsScreen() {
  const { colors, isDarkMode, toggleDarkMode } = useTheme();
  const { user } = useAuth();
  const {
    hasPassword,
    isBiometricEnabled,
    isBiometricAvailable,
    lockTimeout,
    setPassword,
    setBiometricEnabled,
    setLockTimeout,
    removeSecurity
  } = useSecurity();
  const router = useRouter();

  const [isPasswordModalVisible, setIsPasswordModalVisible] = useState(false);
  const [isTimeoutModalVisible, setIsTimeoutModalVisible] = useState(false);
  const [newPIN, setNewPIN] = useState('');
  const [confirmPIN, setConfirmPIN] = useState('');
  const [showPIN, setShowPIN] = useState(false);
  const [showTimePicker, setShowTimePicker] = useState(false);
  
  const { 
    notificationTimes, 
    addNotificationTime, 
    removeNotificationTime, 
    hasPermission, 
    requestPermission 
  } = useNotifications();

  // For guest mode, displayUser is just the local user
  const displayUser = user || { name: 'Guest User', email: 'guest@example.com', imageUrl: null, userId: 'guest' };

  const handleLockToggle = async (value: boolean) => {
    if (value) {
      setIsPasswordModalVisible(true);
    } else {
      Alert.alert(
        'Disable App Lock',
        'Are you sure you want to disable PIN protection?',
        [
          { text: 'Cancel', style: 'cancel' },
          {
            text: 'Disable',
            style: 'destructive',
            onPress: async () => await removeSecurity()
          }
        ]
      );
    }
  };

  const handleSavePIN = async () => {
    if (newPIN.length !== 6 || !/^\d+$/.test(newPIN)) {
      Alert.alert('Error', 'PIN must be exactly 6 digits');
      return;
    }
    if (newPIN !== confirmPIN) {
      Alert.alert('Error', 'PINs do not match');
      return;
    }

    try {
      await setPassword(newPIN);
      setIsPasswordModalVisible(false);
      setNewPIN('');
      setConfirmPIN('');
      Alert.alert('Success', 'Security settings updated');
    } catch (error) {
      Alert.alert('Error', 'Failed to save PIN');
    }
  };

  const handleTimeoutChange = async (timeout: number) => {
    try {
      await setLockTimeout(timeout);
      setIsTimeoutModalVisible(false);
    } catch (error) {
      Alert.alert('Error', 'Failed to update timeout setting');
    }
  };

  const getTimeoutLabel = (timeout: number): string => {
    switch (timeout) {
      case 60000:
        return '1 minute';
      case 300000:
        return '5 minutes';
      case 600000:
        return '10 minutes';
      default:
        return '1 minute';
    }
  };

  const handleTimeChange = async (event: any, selectedTime?: Date) => {
    setShowTimePicker(false);
    if (event.type === 'set' && selectedTime) {
      if (!hasPermission) {
        const granted = await requestPermission();
        if (!granted) {
          Alert.alert('Permission Required', 'Please enable notifications in your device settings.');
          return;
        }
      }
      await addNotificationTime(selectedTime.getHours(), selectedTime.getMinutes());
    }
  };

  const formatTime = (hour: number, minute: number) => {
    const d = new Date();
    d.setHours(hour);
    d.setMinutes(minute);
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const styles = StyleSheet.create({
    container: {
      flex: 1,
      backgroundColor: colors.bg,
    },
    header: {
      backgroundColor: colors.surface,
      padding: 10,
      paddingTop: 40,
      borderBottomWidth: 1,
      borderBottomColor: colors.border,
    },
    headerTitle: {
      fontSize: 24,
      fontWeight: 'bold',
      color: colors.text,
    },
    content: {
