                        {securityChoice === 'biometric' && !securitySetupDone && (
                            <View style={{ marginTop: 16 }}>
                                <TouchableOpacity
                                    style={styles.setupButton}
                                    onPress={handleSetupBiometric}
                                >
                                    <Text style={styles.setupButtonText}>Enable fingerprint</Text>
                                </TouchableOpacity>
