    );

    // ==================== MAIN RENDER ====================
    return (
        <View style={[styles.container, { backgroundColor: isDarkMode ? '#121812' : '#F4FCF4' }]}>
            <Animated.View
                style={[
                    styles.slidesContainer,
                    { transform: [{ translateX: slideAnim }] },
