import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import * as Notifications from 'expo-notifications';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { Platform } from 'react-native';

Notifications.setNotificationHandler({
  handleNotification: async () => ({
    shouldShowAlert: true,
    shouldPlaySound: true,
    shouldSetBadge: false,
    shouldShowBanner: true,
    shouldShowList: true,
  }),
});

interface ParsedTime {
  hour: number;
  minute: number;
  id: string; // Unique identifier for the time slot
}

interface NotificationContextData {
  notificationTimes: ParsedTime[];
  addNotificationTime: (hour: number, minute: number) => Promise<void>;
  removeNotificationTime: (id: string) => Promise<void>;
  hasPermission: boolean;
  requestPermission: () => Promise<boolean>;
}

const NotificationContext = createContext<NotificationContextData | undefined>(undefined);

const STORAGE_KEY = '@tax_naija_notification_times';

const DEFAULT_TIME: ParsedTime = {
  hour: 8, // 8:00 AM
  minute: 0,
  id: 'default-8am',
};

export const NotificationProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [notificationTimes, setNotificationTimes] = useState<ParsedTime[]>([]);
  const [hasPermission, setHasPermission] = useState(false);

  useEffect(() => {
    checkPermissions();
    loadTimes();
  }, []);

  useEffect(() => {
    if (hasPermission) {
      rescheduleAllNotifications(notificationTimes);
    }
  }, [notificationTimes, hasPermission]);

  const checkPermissions = async () => {
    const { status: existingStatus } = await Notifications.getPermissionsAsync();
    let finalStatus = existingStatus;
    if (existingStatus !== 'granted') {
      const { status } = await Notifications.requestPermissionsAsync();
      finalStatus = status;
    }
    setHasPermission(finalStatus === 'granted');
    return finalStatus === 'granted';
  };

  const requestPermission = async () => {
    return await checkPermissions();
  };

  const loadTimes = async () => {
    try {
      const storedTimes = await AsyncStorage.getItem(STORAGE_KEY);
      if (storedTimes) {
        setNotificationTimes(JSON.parse(storedTimes));
      } else {
        // First time app launch, set default time
        setNotificationTimes([DEFAULT_TIME]);
        await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify([DEFAULT_TIME]));
      }
    } catch (error) {
      console.error('Failed to load notification times:', error);
      // Fallback
      setNotificationTimes([DEFAULT_TIME]);
    }
  };

  const saveTimes = async (times: ParsedTime[]) => {
    try {
      await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(times));
      setNotificationTimes(times);
    } catch (error) {
      console.error('Failed to save notification times:', error);
    }
  };

  const addNotificationTime = async (hour: number, minute: number) => {
    const id = `time-${Date.now()}`;
    const newTimes = [...notificationTimes, { hour, minute, id }];
    await saveTimes(newTimes);
  };

  const removeNotificationTime = async (id: string) => {
    const newTimes = notificationTimes.filter(t => t.id !== id);
    await saveTimes(newTimes);
  };

  const rescheduleAllNotifications = async (times: ParsedTime[]) => {
    // Cancel all previously scheduled notifications
    await Notifications.cancelAllScheduledNotificationsAsync();

    if (times.length === 0) return;

    // Schedule new ones
    for (const time of times) {
      await scheduleDailyNotification(time.hour, time.minute);
    }
  };

  const scheduleDailyNotification = async (hour: number, minute: number) => {
    try {
      if (Platform.OS === 'android' || Platform.OS === 'ios') {
        await Notifications.scheduleNotificationAsync({
          content: {
            title: "Tax Reminder!",
            body: "Don't forget to record today's income and expenses in the TaxNaija app.",
            sound: true,
          },
          trigger: {
            type: Notifications.SchedulableTriggerInputTypes.DAILY,
            hour: hour,
            minute: minute,
          },
        });
      }
    } catch (error) {
      console.error('Error scheduling notification for', hour, minute, error);
    }
  };

  return (
    <NotificationContext.Provider
      value={{
        notificationTimes,
        addNotificationTime,
        removeNotificationTime,
        hasPermission,
        requestPermission,
      }}
    >
      {children}
    </NotificationContext.Provider>
  );
};

export const useNotifications = () => {
  const context = useContext(NotificationContext);
  if (context === undefined) {
    throw new Error('useNotifications must be used within a NotificationProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect, ReactNode, useRef } from 'react';
import { AppState, AppStateStatus } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as SecureStore from 'expo-secure-store';
import * as LocalAuthentication from 'expo-local-authentication';
import * as Crypto from 'expo-crypto';
import * as Clipboard from 'expo-clipboard';

interface SecurityContextType {
    isLocked: boolean;
    hasPassword: boolean;
    isBiometricEnabled: boolean;
    isBiometricAvailable: boolean;
    lockTimeout: number;
    unlock: (password: string) => Promise<boolean>;
    authenticateWithBiometrics: () => Promise<boolean>;
    setPassword: (password: string) => Promise<void>;
    setBiometricEnabled: (enabled: boolean) => Promise<void>;
    setLockTimeout: (timeout: number) => Promise<void>;
    removeSecurity: () => Promise<void>;
}

const SecurityContext = createContext<SecurityContextType | undefined>(undefined);

const SECURE_KEYS = {
    PASSWORD: 'local_security_password',
    BIOMETRIC_ENABLED: 'local_security_biometric_enabled',
    LOCK_TIMEOUT: 'local_security_lock_timeout',
    BACKGROUND_TIMESTAMP: 'local_security_background_timestamp',
};

export function SecurityProvider({ children }: { children: ReactNode }) {
    const [isLocked, setIsLocked] = useState(false);
    const [hasPassword, setHasPassword] = useState(false);
    const [isBiometricEnabled, setIsBiometricEnabled] = useState(false);
    const [isBiometricAvailable, setIsBiometricAvailable] = useState(false);
    const [lockTimeout, setLockTimeoutState] = useState(60000); // Default: 1 minute
    const appState = useRef(AppState.currentState);

    useEffect(() => {
        loadSecuritySettings();
        checkBiometrics();

        const subscription = AppState.addEventListener('change', handleAppStateChange);
        return () => subscription.remove();
    }, []);

    const loadSecuritySettings = async () => {
        try {
            const storedPassword = await SecureStore.getItemAsync(SECURE_KEYS.PASSWORD);
            const biometricPref = await SecureStore.getItemAsync(SECURE_KEYS.BIOMETRIC_ENABLED);
            const storedTimeout = await AsyncStorage.getItem(SECURE_KEYS.LOCK_TIMEOUT);

            setHasPassword(!!storedPassword);
            setIsBiometricEnabled(biometricPref === 'true');
            setLockTimeoutState(storedTimeout ? parseInt(storedTimeout, 10) : 60000);

            if (!!storedPassword) {
                setIsLocked(true);
            }
        } catch (error) {
            console.error('Failed to load security settings', error);
        }
    };

    const checkBiometrics = async () => {
        const compatible = await LocalAuthentication.hasHardwareAsync();
        const enrolled = await LocalAuthentication.isEnrolledAsync();
        setIsBiometricAvailable(compatible && enrolled);
    };

    const handleAppStateChange = async (nextAppState: AppStateStatus) => {
        if (
            appState.current.match(/active/) &&
            nextAppState.match(/inactive|background/)
        ) {
            // App went to background
            // 1. Clear clipboard to prevent sensitive data leakage
            await Clipboard.setStringAsync('');
            
            // 2. Store timestamp for auto-lock
            const password = await SecureStore.getItemAsync(SECURE_KEYS.PASSWORD);
            if (password) {
                await AsyncStorage.setItem(SECURE_KEYS.BACKGROUND_TIMESTAMP, Date.now().toString());
            }
        } else if (
            appState.current.match(/inactive|background/) &&
            nextAppState === 'active'
        ) {
            // App came back to foreground, check if timeout elapsed
            const password = await SecureStore.getItemAsync(SECURE_KEYS.PASSWORD);
            if (password) {
                const backgroundTimestamp = await AsyncStorage.getItem(SECURE_KEYS.BACKGROUND_TIMESTAMP);
                if (backgroundTimestamp) {
                    const elapsedTime = Date.now() - parseInt(backgroundTimestamp, 10);
                    if (elapsedTime >= lockTimeout) {
                        setIsLocked(true);
                    }
                    // Clear the timestamp
                    await AsyncStorage.removeItem(SECURE_KEYS.BACKGROUND_TIMESTAMP);
                }
            }
        }
        appState.current = nextAppState;
    };
    
    // Hash PIN before storing or comparing
    const hashPIN = async (pin: string): Promise<string> => {
        return await Crypto.digestStringAsync(
            Crypto.CryptoDigestAlgorithm.SHA256,
            pin
        );
    };

    const unlock = async (password: string): Promise<boolean> => {
        try {
            const storedPassword = await SecureStore.getItemAsync(SECURE_KEYS.PASSWORD);
            if (!storedPassword) return false;
            
            // Backwards compatibility check: IF the stored password is 6 digits long, it's plainly stored.
            // A SHA-256 hash will be 64 characters long hex string.
            if (storedPassword.length === 6) {
                if (storedPassword === password) {
                    // It matched! Let's migrate them to hashed format right away
                    await setPassword(password);
                    setIsLocked(false);
                    return true;
                }
            } else {
                // Otherwise we assume it's hashed
                const hashedAttempt = await hashPIN(password);
                if (storedPassword === hashedAttempt) {
                    setIsLocked(false);
                    return true;
                }
            }
            return false;
        } catch (error) {
            console.error('Unlock failed', error);
            return false;
        }
    };

    const authenticateWithBiometrics = async (): Promise<boolean> => {
        if (!isBiometricAvailable || !isBiometricEnabled) return false;

        try {
            const result = await LocalAuthentication.authenticateAsync({
                promptMessage: 'Unlock Tax Calculator',
                fallbackLabel: 'Use PIN',
            });

            if (result.success) {
                setIsLocked(false);
                return true;
            }
            return false;
        } catch (error) {
            console.error('Biometric auth failed', error);
            return false;
        }
    };

    const setPassword = async (password: string) => {
        const hashedPIN = await hashPIN(password);
        await SecureStore.setItemAsync(SECURE_KEYS.PASSWORD, hashedPIN);
        setHasPassword(true);
        setIsLocked(false);
    };

    const setBiometricEnabled = async (enabled: boolean) => {
        await SecureStore.setItemAsync(SECURE_KEYS.BIOMETRIC_ENABLED, String(enabled));
        setIsBiometricEnabled(enabled);
    };

    const setLockTimeout = async (timeout: number) => {
        await AsyncStorage.setItem(SECURE_KEYS.LOCK_TIMEOUT, timeout.toString());
        setLockTimeoutState(timeout);
    };

    const removeSecurity = async () => {
        await SecureStore.deleteItemAsync(SECURE_KEYS.PASSWORD);
        await SecureStore.deleteItemAsync(SECURE_KEYS.BIOMETRIC_ENABLED);
        await AsyncStorage.removeItem(SECURE_KEYS.LOCK_TIMEOUT);
        await AsyncStorage.removeItem(SECURE_KEYS.BACKGROUND_TIMESTAMP);
        setHasPassword(false);
        setIsLocked(false);
        setIsBiometricEnabled(false);
    };

    return (
        <SecurityContext.Provider
            value={{
                isLocked,
                hasPassword,
                isBiometricEnabled,
                isBiometricAvailable,
                lockTimeout,
                unlock,
                authenticateWithBiometrics,
                setPassword,
                setBiometricEnabled,
                setLockTimeout,
                removeSecurity,
            }}
        >
            {children}
        </SecurityContext.Provider>
    );
}

export function useSecurity() {
    const context = useContext(SecurityContext);
    if (context === undefined) {
        throw new Error('useSecurity must be used within a SecurityProvider');
    }
    return context;
}

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { TaxBreakdown, IncomeType, CalculationHistoryItem } from '@/types/taxTypes';

const CACHE_KEY = 'tax_history_cache';

interface TaxHistoryContextType {
    data: CalculationHistoryItem[] | null;
    isLoading: boolean;
    refreshing: boolean;
    refresh: () => Promise<void>;
    addCalculation: (newCalc: any) => Promise<void>;
    deleteCalculation: (id: string) => Promise<void>;
}

const TaxHistoryContext = createContext<TaxHistoryContextType | undefined>(undefined);

export function TaxHistoryProvider({ children }: { children: ReactNode }) {
    const [data, setData] = useState<CalculationHistoryItem[] | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [refreshing, setRefreshing] = useState(false);

    const loadHistory = async () => {
        try {
            const jsonValue = await AsyncStorage.getItem(CACHE_KEY);
            if (jsonValue != null) {
                setData(JSON.parse(jsonValue));
            } else {
                setData([]);
            }
        } catch (e) {
            console.error("Failed to load tax history", e);
            setData([]);
        } finally {
            setIsLoading(false);
            setRefreshing(false);
        }
    };

    useEffect(() => {
        loadHistory();
    }, []);

    const refresh = async () => {
        setRefreshing(true);
        await loadHistory();
    };

    const addCalculation = async (newCalc: any) => {
        let updatedHistory;

        if (newCalc._id) {
            // Update existing entry
            updatedHistory = (data || []).map(item =>
                item._id === newCalc._id ? { ...item, ...newCalc } : item
            );
        } else {
            // Create new entry
            const entry = {
                ...newCalc,
                _id: Date.now().toString(),
                createdAt: Date.now(),
            };
            updatedHistory = [entry, ...(data || [])];
        }

        setData(updatedHistory); // Optimistic update

        try {
            await AsyncStorage.setItem(CACHE_KEY, JSON.stringify(updatedHistory));
        } catch (e) {
            console.error("Failed to save calculation", e);
            // Revert on error if necessary
        }
    };

    const deleteCalculation = async (id: string) => {
        if (!data) return;

        const updatedHistory = data.filter(item => item._id !== id);
        setData(updatedHistory); // Optimistic update

        try {
            await AsyncStorage.setItem(CACHE_KEY, JSON.stringify(updatedHistory));
        } catch (e) {
            console.error("Failed to delete calculation", e);
        }
    };

    return (
        <TaxHistoryContext.Provider
            value={{
                data,
                isLoading,
                refreshing,
                refresh,
                addCalculation,
                deleteCalculation,
            }}
        >
            {children}
        </TaxHistoryContext.Provider>
    );
}

export function useTaxHistory() {
    const context = useContext(TaxHistoryContext);
    if (context === undefined) {
        throw new Error('useTaxHistory must be used within a TaxHistoryProvider');
    }
    return context;
}

